// Verificar se recebemos o ID do job assíncrono
const input = $input.first().json;

if (input.error || input.code) {
  const errorMsg = input.error?.message || input.message || JSON.stringify(input.error || input);
  return [{ json: { 
    jobError: true, 
    errorMessage: `Erro ao iniciar busca na Outscraper: ${errorMsg}` 
  }}];
}

// async=true retorna { id: 'job-id', status: 'Pending', ... }
if (!input.id) {
  // Pode ser que retornou síncrono mesmo com async=true (dados pequenos)
  if (input.data && Array.isArray(input.data)) {
    return [{ json: { 
      jobError: false,
      jobId: null,
      syncData: input.data // dados já disponíveis
    }}];
  }
  return [{ json: { 
    jobError: true, 
    errorMessage: 'Resposta inesperada da Outscraper: sem ID de job e sem dados.' 
  }}];
}

return [{ json: { 
  jobError: false,
  jobId: input.id,
  syncData: null
}}];

