// Verificar se os dados já vieram de forma síncrona (job pequeno)
const input = $input.first().json;

if (input.syncData && Array.isArray(input.syncData)) {
  return [{ json: { hasSyncData: true, data: input.syncData, jobId: null } }];
}

return [{ json: { hasSyncData: false, jobId: input.jobId } }];

// Aguardar 5 segundos e verificar status do job
const pollResult = $input.first().json;

// Se ainda está processando, retornar sinal de retry
if (pollResult.status === 'Pending' || pollResult.status === 'Running') {
  return [{ json: { isPending: true, jobId: $('Check Sync Data').first().json.jobId } }];
}

// Job concluído — extrair dados
if (pollResult.data && Array.isArray(pollResult.data)) {
  return [{ json: { isPending: false, data: pollResult.data } }];
}

// Job falhou
return [{ json: { 
  isPending: false,
  data: null,
  error: `Job Outscraper falhou. Status: ${pollResult.status || 'desconhecido'}` 
}}];

// Unificar dados de ambos os caminhos (sync ou poll)
const syncData = (() => {
  try { return $('IF - Sync ou Async').first().json.data; } catch (e) { return null; }
})();

const pollData = (() => {
  try { return $('Check Poll Status').first().json.data; } catch (e) { return null; }
})();

const data = syncData || pollData;

if (!data || !Array.isArray(data) || data.length === 0) {
  return [{ json: { apiError: false, noResults: true, data: [] } }];
}

const firstBatch = data[0];
if (!firstBatch || !Array.isArray(firstBatch) || firstBatch.length === 0) {
  return [{ json: { apiError: false, noResults: true, data: data } }];
}

return [{ json: { apiError: false, noResults: false, data: data } }];

const tenantId = $('Webhook').first().json.body.tenantId;
const city = $('Webhook').first().json.body.city;
const state = $('Webhook').first().json.body.state;

const validatedData = $('Unificar Dados').first().json;
if (validatedData.noResults) {
  return [{ json: { summary: { found: 0, created: 0, duplicates: 0 }, tenantId } }];
}

const leads = validatedData.data[0];

const existingOpps = $input.all().map(e => e.json).filter(e => e && !e.error);

let validLeads = [];
let duplicates = 0;

leads.forEach(lead => {
  if (!lead || !lead.name) return;

  // BLINDAGEM DA FONTE: Só aceita o lead se houver pelo menos uma forma de contato
  const hasContact = lead.phone || lead.site || lead.email;
  if (!hasContact) return; // Descarta lead sem contato

  const isDup = existingOpps.some(e => 
    (e.phone && lead.phone && e.phone === lead.phone) || 
    (e.website && lead.site && e.website === lead.site)
  );
  if (isDup) {
    duplicates++;
  } else {
    let score = 0;
    if (lead.phone) score += 15;
    if (lead.site) score += 20;
    if (lead.rating >= 4.0) score += 20;
    if (lead.reviews >= 50) score += 15;
    if (lead.full_address) score += 10;
    if (lead.type) score += 20;

    validLeads.push({
      tenant_id: tenantId,
      company_name: lead.name,
      phone: lead.phone || null,
      website: lead.site || null,
      address: lead.full_address || null,
      city: city,
      state: state,
      rating_value: lead.rating || null,
      rating_count: lead.reviews || null,
      google_maps_url: lead.business_url || null,
      category: lead.type || null,
      origin: 'Google Maps',
      source_service: 'Outscraper',
      status: score >= 60 ? 'scored' : 'discovered',
      score: score
    });
  }
});

if (validLeads.length === 0) {
  return [{ json: { summary: { found: leads.length, created: 0, duplicates: duplicates }, tenantId } }];
}

return validLeads.map(l => ({ json: { ...l, summary: { found: leads.length, created: validLeads.length, duplicates } } }));

const items = $input.all();
const summary = items[0]?.json?.summary || { found: 0, created: 0, duplicates: 0 };
const tenantId = $('Webhook').first().json.body.tenantId;

const creditsRow = $('Supabase - Get Credits').first().json;

let oldUsed = 0;
let weight = 1;
try {
  oldUsed = parseInt(creditsRow.opportunity_used) || 0;
  weight = parseInt(creditsRow.weight_outscraper_search) || 1;
} catch (e) {}

const newUsed = oldUsed + weight;

return [{ json: { summary, tenantId, newUsed, weight } }];

